const items = $input.all();

const artigos = items.map(item => {
  const xml = item.json.data || '';

  // Isola cada notícia separadamente
  const xmlItems = [...xml.matchAll(/<item>(.*?)<\/item>/gs)].map(m => m[1]);

  return xmlItems.map(xmlItem => {
    // Busca dados textuais
    const tituloMatch = xmlItem.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/s) || xmlItem.match(/<title>(.*?)<\/title>/s);
    const linkMatch = xmlItem.match(/<link>(https?:\/\/[^<]+)<\/link>/);
    const descMatch = xmlItem.match(/<description><!\[CDATA\[(.*?)\]\]><\/description>/s) || xmlItem.match(/<description>(.*?)<\/description>/s);
    const dateMatch = xmlItem.match(/<pubDate>(.*?)<\/pubDate>/);

    let imagemUrl = '';

    // Tenta encontrar a imagem original no XML
    const regexImagensBrutas = /https?:\/\/[^"'\s><\[\]]+(?:jpg|jpeg|png|webp)[^"'\s><\[\]]*/gi;
    const todasAsImagens = xmlItem.match(regexImagensBrutas) || [];
    const imagensValidas = todasAsImagens.filter(url => 
      !url.includes('gravatar.com') && 
      !url.includes('w3.org') &&
      !url.includes('icon') &&
      !url.includes('logo')
    );

    if (imagensValidas.length > 0) {
      imagemUrl = imagensValidas[0];
    } else {
      const mediaMatch = xmlItem.match(/<media:(?:content|thumbnail)[^>]+url=["']([^"']+)["']/i);
      if (mediaMatch) imagemUrl = mediaMatch[1];
    }

    if (imagemUrl) {
      imagemUrl = imagemUrl.replace(/&amp;/g, '&');
    }

    const tituloFinal = tituloMatch ? tituloMatch[1].trim() : 'Artificial Intelligence';

    // Imagem Dinâmica
    if (!imagemUrl) {
      const promptBusca = `Modern technology, artificial intelligence concept, ${tituloFinal}`;
      imagemUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(promptBusca)}?width=600&height=350&nologo=true`;
    }

    return {
      titulo: tituloFinal,
      link: linkMatch ? linkMatch[1].trim() : '',
      descricao: descMatch ? descMatch[1].replace(/<[^>]+>/g, '').slice(0, 300).trim() : '',
      dataPublicacao: dateMatch ? dateMatch[1].trim() : '',
      imagemUrl: imagemUrl, 
      categoria: 'Sem Categoria',
      fonte: 'TechCrunch'
    };
  });
});

// Limpa itens inválidos e restringe a saída aos 5 primeiros artigos
const flat = artigos.flat()
  .filter(a => a.titulo !== 'Artificial Intelligence')
  .slice(0, 8);

return flat.map(a => ({ json: a }));

