const items = $input.all();
const resultado = [];

for (const item of items) {
  try {
    // 1. MELHORIA: Busca o texto de forma mais robusta, cobrindo o padrão do LangChain/Groq
    let texto = item.json.message?.content || item.json.text || item.json.output || item.json.content || '';

    // Converte para string por segurança caso a IA retorne um objeto direto
    if (typeof texto !== 'string') {
        texto = JSON.stringify(texto);
    }

    // Remove possíveis markdown code blocks
    texto = texto.replace(/```json/g, '').replace(/```/g, '').trim();

    // Faz o parse do JSON
    const parsed = JSON.parse(texto);

    resultado.push({ json: parsed });
  } catch (e) {
    // 2. MELHORIA: Mantém a estrutura com imagemUrl para não quebrar o HTML seguinte
    resultado.push({
      json: {
        titulo: 'Erro ao processar',
        tituloCriativo: 'Erro no Processamento',
        resumo: 'Não foi possível processar este artigo com a IA.',
        categoria: 'Sem Categoria',
