    .replace(/[\u4e00-\u9fff]/g, '') // Remove chinês
    .replace(/[\u3040-\u309f]/g, '') // Remove japonês hiragana
    .replace(/[\u30a0-\u30ff]/g, '') // Remove japonês katakana
    .replace(/[\u0400-\u04ff]/g, '') // Remove cirílico
    .replace(/[\u0600-\u06ff]/g, '') // Remove árabe
    .trim();

  return {
    titulo: repo.full_name || '',
    link: repo.html_url || '',
    descricao: descricaoLimpa || 'Repositório de IA no GitHub',
    dataPublicacao: repo.updated_at || '',
    categoria: 'Sem Categoria',
    estrelas: repo.stargazers_count || 0,
    linguagem: repo.language || 'N/A',
    fonte: 'GitHub Trending'
  };
});

return extraidos.map(a => ({ json: a }));

