  const link = (entrada.match(/<link[^>]*href="([^"]*)"/) || [])[1] || '';
  const data = (entrada.match(/<updated>(.*?)<\/updated>/) || [])[1] || '';
  const descricao = (entrada.match(/<summary[^>]*>([\s\S]*?)<\/summary>/) || [])[1] || '';
  const conteudo = (entrada.match(/<content[^>]*>([\s\S]*?)<\/content>/) || [])[1] || '';

  return {
    titulo: titulo.replace(/<!\[CDATA\[(.*?)\]\]>/g, '$1').trim(),
    link: link.trim(),
    descricao: (descricao || conteudo).replace(/<[^>]+>/g, '').replace(/&[^;]+;/g, ' ').slice(0, 300).trim(),
    dataPublicacao: data.trim(),
    categoria: 'Sem Categoria',
    fonte: 'The Verge AI'
  };
}).filter(a => {
  const textoCompleto = (a.titulo + ' ' + a.descricao).toLowerCase();
  return palavrasChaveIA.some(palavra => textoCompleto.includes(palavra));
});

return artigos.slice(0, 5).filter(a => a.titulo).map(a => ({ json: a }));

